import React from "react";

export default function DashboardPage() {
  return (
    <div
      style={{
        minHeight: "100vh",
        backgroundColor: "#020617",
        color: "white",
        padding: "40px",
        fontFamily: "Arial",
      }}
    >
      <h1 style={{ fontSize: "48px", marginBottom: "20px" }}>
        Dashboard 🚀
      </h1>

      <p style={{ color: "#94a3b8", marginBottom: "40px" }}>
        Welcome to AI Startup Advisor
      </p>

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit, minmax(250px, 1fr))",
          gap: "20px",
        }}
      >
        <div
          style={{
            background: "#1e293b",
            padding: "25px",
            borderRadius: "16px",
          }}
        >
          <h2>Startup Stage</h2>
          <p>Active</p>
        </div>

        <div
          style={{
            background: "#1e293b",
            padding: "25px",
            borderRadius: "16px",
          }}
        >
          <h2>AI Chats</h2>
          <p>0 Sessions</p>
        </div>

        <div
          style={{
            background: "#1e293b",
            padding: "25px",
            borderRadius: "16px",
          }}
        >
          <h2>Goals</h2>
          <p>0 Goals</p>
        </div>
      </div>
    </div>
  );
}
